const threshold = $('Set Thresholds').first().json;
const weekRows = $('Get Week Budget vs Spend').all();
const categories = $('Get Category Pace').all().map(i => i.json);

const flags = [];

if (weekRows.length) {
  const w = weekRows[0].json;
  const totalBudget = Number(w.weekly_budget) + Number(w.weekend_budget);
  const totalSpent = Number(w.weekday_spent) + Number(w.weekend_spent);
  const pctUsed = totalBudget > 0 ? (totalSpent / totalBudget) * 100 : 0;
  const pctElapsed = (Number(w.iso_day_of_week) / 7) * 100;
  const pctRemaining = 100 - pctElapsed;
  if (totalBudget > 0 && pctUsed >= threshold.pctBudgetUsedThreshold && pctRemaining > threshold.pctTimeRemainingThreshold) {
    flags.push(`Week ${w.week_number} discretionary pool: R${totalSpent.toFixed(2)} of R${totalBudget.toFixed(2)} used (${pctUsed.toFixed(0)}%) with ${pctRemaining.toFixed(0)}% of the week still to go.`);
  }
}

const today = new Date();
const dayOfMonth = today.getDate();
const daysInMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();
const isoDow = ((today.getDay() + 6) % 7) + 1; // Mon=1..Sun=7

for (const cat of categories) {
  const pctElapsed = cat.period === 'weekly' ? (isoDow / 7) * 100 : (dayOfMonth / daysInMonth) * 100;
  const pctRemaining = 100 - pctElapsed;
  const budget = Number(cat.budget_amount);
  const spent = Number(cat.period_spent);
  const pctUsed = budget > 0 ? (spent / budget) * 100 : 0;
  if (pctUsed >= threshold.pctBudgetUsedThreshold && pctRemaining > threshold.pctTimeRemainingThreshold) {
    const periodLabel = cat.period === 'weekly' ? 'week' : 'month';
    flags.push(`${cat.name} (${cat.period}): R${spent.toFixed(2)} of R${budget.toFixed(2)} used (${pctUsed.toFixed(0)}%) with ${pctRemaining.toFixed(0)}% of the ${periodLabel} still to go.`);
  }
}

if (flags.length === 0) {
  // Return zero items so the downstream Telegram node is skipped entirely.
  // Deliberately NOT an IF node on a shouldSend flag: in this n8n version an
  // IF node's empty TRUE branch non-deterministically still fired the Telegram
  // send with empty text (observed: identical input, run A skipped it, run B
  // errored). An empty single-output is the reliable 'skip downstream' pattern.
  return [];
}

const message = ['💰 Budget check-in:', '', ...flags.map((f) => `⚠️ ${f}`)].join('\n');
return [{ json: { message } }];
